namespace sv_3f0e7b8d3e55433ba0b91018c08ec9bc.Client.Auth;

public sealed class UserInfo
{
    public string Name { get; set; } = string.Empty;
    public string[] Roles { get; set; } = [];
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_3f0e7b8d3e55433ba0b91018c08ec9bc.Client.Auth;

/// <summary>
/// Reads the persisted auth state that was serialized by the server during prerendering.
/// This ensures the user's identity and roles survive the transition to WebAssembly.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>("UserInfo", out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Name),
                new(ClaimTypes.Email, userInfo.Name),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, "Persisted");
            var user = new ClaimsPrincipal(identity);
            _authenticationStateTask = Task.FromResult(new AuthenticationState(user));
        }
        else
        {
            _authenticationStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_3f0e7b8d3e55433ba0b91018c08ec9bc.Client.Auth;

namespace sv_3f0e7b8d3e55433ba0b91018c08ec9bc.Auth;

/// <summary>
/// Server-side auth state provider that simulates a logged-in user and persists
/// the auth state via PersistentComponentState so the WASM client can pick it up.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private Task<AuthenticationState>? _authStateTask;

    public HardcodedAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _persistentState.RegisterOnPersisting(PersistAuthStateAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        return Task.FromResult(new AuthenticationState(user));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task PersistAuthStateAsync()
    {
        var authState = _authStateTask is not null
            ? await _authStateTask
            : await GetAuthenticationStateAsync();

        var principal = authState.User;
        if (principal.Identity?.IsAuthenticated != true)
            return;

        _persistentState.PersistAsJson("UserInfo", new UserInfo
        {
            Name = principal.FindFirst(ClaimTypes.Name)?.Value ?? string.Empty,
            Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
        });
    }

    public void Dispose()
    {
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h4>Roles</h4>
        <ul>
            @foreach (var role in context.User.FindAll(ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor Page</h1>
<p>Welcome to the editor area. You have the <strong>Editor</strong> role.</p>

